"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[74897],{86089:e=>{e.exports=JSON.parse('{"tag":{"label":"lighting","permalink":"/dst-api-webdocs/docs/tags/lighting","allTagsPath":"/dst-api-webdocs/docs/tags","count":15,"items":[{"id":"game-scripts/components/ambientlighting","title":"Ambientlighting","description":"Manages dynamic ambient lighting color transitions based on world phase, moon phase, season, weather, and player night vision state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ambientlighting"},{"id":"game-scripts/behaviours/avoidlight","title":"Avoidlight","description":"Controls an entity\'s movement to avoid being in direct light by changing direction periodically or when transitioning between light and shadow.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/avoidlight"},{"id":"game-scripts/components/bloomer","title":"Bloomer","description":"Manages bloom effect stacking and propagation for entities and their children, supporting priority-based bloom layering and automatic cleanup on source removal.","permalink":"/dst-api-webdocs/docs/game-scripts/components/bloomer"},{"id":"game-scripts/components/canopylightrays","title":"Canopylightrays","description":"Spawns and manages reusable light ray prefabs in a radial area around the owner entity for visual canopy effects.","permalink":"/dst-api-webdocs/docs/game-scripts/components/canopylightrays"},{"id":"game-scripts/components/canopyshadows","title":"Canopyshadows","description":"Manages the spawning and despawning of leaf canopy shadow tiles around an entity within a configurable radius.","permalink":"/dst-api-webdocs/docs/game-scripts/components/canopyshadows"},{"id":"game-scripts/components/colourcube","title":"Colourcube","description":"Manages dynamic colour grading via colour cubes (LUTs) to reflect in-game conditions such as time of day, season, sanity, and environment (caves or overworld).","permalink":"/dst-api-webdocs/docs/game-scripts/components/colourcube"},{"id":"game-scripts/components/firefx","title":"Firefx","description":"Manages visual and audio effects for fire-based entities, including dynamic lighting, sound, and animation transitions across multiple intensity levels.","permalink":"/dst-api-webdocs/docs/game-scripts/components/firefx"},{"id":"game-scripts/components/freezefx","title":"Freezefx","description":"Manages dynamic visual and audio effects for fire-based entities, including flickering light, radius scaling, intensity control, and sound effects across multiple flame levels.","permalink":"/dst-api-webdocs/docs/game-scripts/components/freezefx"},{"id":"game-scripts/components/lightpostpartner","title":"Lightpostpartner","description":"Manages shackle relationships between a lantern post and connected light sources in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lightpostpartner"},{"id":"game-scripts/components/nightlightmanager","title":"Nightlightmanager","description":"Manages registration, tracking, and filtering of night light entities within the world for master simulation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/nightlightmanager"},{"id":"game-scripts/components/playervision","title":"Playervision","description":"Manages player visual modifiers (e.g., night vision, ghost vision, nightmare vision) by controlling colour cube overrides and related events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playervision"},{"id":"game-scripts/components/pumpkincarvable","title":"Pumpkincarvable","description":"Manages carving, visual rendering, and state persistence of pumpkins in the game, including cut shapes, lighting effects, and synchronization between client and server.","permalink":"/dst-api-webdocs/docs/game-scripts/components/pumpkincarvable"},{"id":"game-scripts/components/vase","title":"Vase","description":"Manages flower placement, wilting behavior, and dynamic lighting for decorative vases in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/components/vase"},{"id":"game-scripts/components/vaulttorchgrid","title":"Vaulttorchgrid","description":"Manages a grid of vault torch entities and their state persistence in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/vaulttorchgrid"},{"id":"game-scripts/components/weather","title":"Weather","description":"Manages dynamic weather systems including precipitation, temperature, moisture, wetness, snow accumulation, lightning, and atmospheric lighting.","permalink":"/dst-api-webdocs/docs/game-scripts/components/weather"}],"unlisted":false}}')}}]);